CREATE TYPE "TxStatus" AS ENUM ('DETECTED','PENDING','CONFIRMING','CONFIRMED','SWAP_QUEUED','SWAPPING','SWAPPED','WITHDRAW_QUEUED','WITHDRAWING','WITHDRAWN','FAILED','MANUAL_REVIEW');
CREATE TABLE "LtcTransaction" ("id" TEXT NOT NULL,"txHash" TEXT NOT NULL,"trackId" TEXT,"address" TEXT NOT NULL,"amountLtc" DECIMAL(30,12) NOT NULL,"confirmations" INTEGER NOT NULL DEFAULT 0,"status" "TxStatus" NOT NULL DEFAULT 'DETECTED',"provider" TEXT NOT NULL DEFAULT 'oxapay',"raw" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "LtcTransaction_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "LtcTransaction_txHash_key" ON "LtcTransaction"("txHash");
CREATE TABLE "SwapRecord" ("id" TEXT NOT NULL,"txId" TEXT NOT NULL,"provider" TEXT NOT NULL,"fromCurrency" TEXT NOT NULL,"toCurrency" TEXT NOT NULL,"fromAmount" DECIMAL(30,12) NOT NULL,"toAmount" DECIMAL(30,12) NOT NULL,"fee" DECIMAL(30,12),"providerOrderId" TEXT,"raw" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "SwapRecord_pkey" PRIMARY KEY ("id"));
CREATE TABLE "WithdrawalRecord" ("id" TEXT NOT NULL,"txId" TEXT NOT NULL,"provider" TEXT NOT NULL,"currency" TEXT NOT NULL,"network" TEXT NOT NULL,"amount" DECIMAL(30,12) NOT NULL,"fee" DECIMAL(30,12),"destination" TEXT NOT NULL,"providerWithdrawalId" TEXT,"txHash" TEXT,"status" TEXT NOT NULL,"raw" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "WithdrawalRecord_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AuditLog" ("id" TEXT NOT NULL,"actor" TEXT NOT NULL,"action" TEXT NOT NULL,"details" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AuditLog_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Setting" ("key" TEXT NOT NULL,"value" TEXT NOT NULL,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Setting_pkey" PRIMARY KEY ("key"));
ALTER TABLE "SwapRecord" ADD CONSTRAINT "SwapRecord_txId_fkey" FOREIGN KEY ("txId") REFERENCES "LtcTransaction"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "WithdrawalRecord" ADD CONSTRAINT "WithdrawalRecord_txId_fkey" FOREIGN KEY ("txId") REFERENCES "LtcTransaction"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
